final:
module fir_filter (
    input [4:0] in_sample,          // current input sample
    input [4:0] x1,         // previous input sample
    input [4:0] x2,         // input sample before previous
    output reg [4:0] y      // output sample
);

always @(*) begin
    y = (in_sample * 1 + x1 * 2 + x2 * 1) >> 1;
end
endmodule
